#!/usr/bin/env python3
"""SQL Query CLI for multiple file formats."""

import argparse
import sys
from pathlib import Path

import pandas as pd
from database import CSVDatabase
from query_executor import SQLExecutor


def load_sql_query(sql_arg: str) -> str:
    sql_path = Path(sql_arg)
    if sql_path.exists():
        return sql_path.read_text()
    return sql_arg


def format_as_markdown(df) -> str:
    if df.empty:
        return ""

    headers = list(df.columns)
    lines = [
        "| " + " | ".join(str(h) for h in headers) + " |",
        "| " + " | ".join(["---"] * len(headers)) + " |",
    ]

    for _, row in df.iterrows():
        cells = ["NULL" if pd.isna(row[col]) else str(row[col]) for col in headers]
        lines.append("| " + " | ".join(cells) + " |")

    return "\n".join(lines)


def parse_sharded_arg(sharded_str: str) -> tuple:
    if '=' not in sharded_str:
        raise ValueError(f"Invalid --sharded format: '{sharded_str}'. Expected '<table_name>=<glob_pattern>'")
    table_name, pattern = sharded_str.split('=', 1)
    if not table_name.strip():
        raise ValueError(f"Empty table name in --sharded: '{sharded_str}'")
    if not pattern.strip():
        raise ValueError(f"Empty glob pattern in --sharded: '{sharded_str}'")
    return (table_name.strip(), pattern.strip())


def main():
    parser = argparse.ArgumentParser(description="Run SQL queries on CSV files")
    parser.add_argument('--data', required=True, help='Directory containing CSV files')
    parser.add_argument('--sql', required=True, help='SQL query or path to SQL file')
    parser.add_argument('--out', help='Output file path for CSV result')
    parser.add_argument('--sharded', action='append', default=[],
                       help='Sharded table definition: <table_name>=<glob_pattern>. Can be specified multiple times.')
    args = parser.parse_args()

    sharded_configs = []
    for sharded_arg in args.sharded:
        try:
            sharded_configs.append(parse_sharded_arg(sharded_arg))
        except ValueError as e:
            print(f"Error: {e}", file=sys.stderr)
            sys.exit(1)

    if not Path(args.data).is_dir():
        print(f"Error: Data directory '{args.data}' does not exist", file=sys.stderr)
        sys.exit(1)

    try:
        sql = load_sql_query(args.sql)
    except Exception as e:
        print(f"Error loading SQL: {e}", file=sys.stderr)
        sys.exit(1)

    try:
        db = CSVDatabase(args.data)
        if sharded_configs:
            db.load_sharded_tables(sharded_configs)
        if not db.tables:
            print("Error: No valid CSV files found in data directory", file=sys.stderr)
            sys.exit(1)
    except Exception as e:
        print(f"Error loading data: {e}", file=sys.stderr)
        sys.exit(1)

    try:
        result = SQLExecutor(db).execute(sql)
        print(format_as_markdown(result))
        if args.out:
            result.to_csv(args.out, index=False)
    except Exception as e:
        print(f"Error executing query: {e}", file=sys.stderr)
        sys.exit(1)


if __name__ == '__main__':
    main()

"""SQL query parser using sqlparse."""

import re
import sqlparse
from sqlparse.sql import Identifier
from sqlparse.tokens import Keyword
from typing import Any

_KEYWORDS = {'AND', 'OR', 'NOT', 'SELECT', 'FROM', 'WHERE', 'GROUP', 'HAVING', 'ORDER',
             'LIMIT', 'OFFSET', 'INNER', 'LEFT', 'RIGHT', 'FULL', 'JOIN', 'ON', 'BY', 'ASC', 'DESC'}


def parse_query(sql: str) -> dict:
    """Parse SQL into structured query plan."""
    stmt = sqlparse.parse(sql.strip())[0]
    return {
        'select': _parse_select(stmt),
        'from': _parse_from(stmt),
        'where': _extract_expression(stmt, 'WHERE', ['GROUP', 'HAVING', 'ORDER', 'LIMIT', 'OFFSET']),
        'group_by': _parse_list(stmt, 'GROUP', ['BY', 'HAVING', 'ORDER', 'LIMIT', 'OFFSET']),
        'having': _extract_expression(stmt, 'HAVING', ['ORDER', 'LIMIT', 'OFFSET']),
        'order_by': _parse_order_by(stmt),
        'limit': _parse_number(stmt, 'LIMIT', ['OFFSET']),
        'offset': _parse_number(stmt, 'OFFSET', ['LIMIT']),
    }


def _extract_expression(stmt, keyword: str, stop_keywords: list) -> str:
    in_clause = False
    parts = []
    for token in stmt.flatten():
        if token.ttype in Keyword:
            if token.value.upper() == keyword:
                in_clause = True
                continue
            elif token.value.upper() in stop_keywords:
                in_clause = False
        if in_clause and token.value.strip():
            parts.append(token.value)
    return ' '.join(parts).strip()


def _parse_list(stmt, keyword: str, stop_keywords: list) -> list:
    items = []
    in_list = False
    for token in stmt.flatten():
        if token.ttype in Keyword:
            if token.value.upper() == keyword:
                in_list = True
                continue
            elif token.value.upper() in stop_keywords:
                in_list = False
        if in_list and token.value.strip() and token.value.strip() != ',':
            items.append(token.value.strip())
    return items


def _parse_number(stmt, keyword: str, stop_keywords: list) -> int | None:
    in_clause = False
    for token in stmt.flatten():
        if token.ttype in Keyword:
            if token.value.upper() == keyword:
                in_clause = True
                continue
            elif token.value.upper() in stop_keywords:
                in_clause = False
        if in_clause and token.value.strip():
            val = token.value.strip()
            if val.isdigit() or (val.startswith('-') and val[1:].isdigit()):
                return int(val)
    return None


def _parse_select(stmt) -> tuple:
    selects = []
    distinct = False
    in_select = False
    for token in stmt.flatten():
        if token.ttype in Keyword and token.value.upper() == 'SELECT':
            in_select = True
            continue
        elif token.ttype in Keyword and token.value.upper() in ['FROM', 'WHERE', 'GROUP', 'HAVING', 'ORDER', 'LIMIT', 'OFFSET']:
            in_select = False
            continue
        if in_select and token.value.strip():
            val = token.value.strip()
            if val.upper() == 'DISTINCT':
                distinct = True
            else:
                selects.append(val)
    return selects, distinct


def _parse_from(stmt) -> dict:
    result = {'main_table': None, 'joins': []}
    in_from = False
    in_join = False
    join_type = 'INNER'
    current_join = None

    for token in stmt.tokens:
        if token.ttype in Keyword:
            val = token.value.upper()
            if val == 'FROM':
                in_from = True
                in_join = False
            elif val in ['INNER', 'LEFT', 'RIGHT', 'FULL']:
                join_type = val
            elif val == 'JOIN':
                in_join = True
            elif val == 'ON':
                if current_join:
                    current_join['in_on'] = True
            elif val in ['WHERE', 'GROUP', 'HAVING', 'ORDER', 'LIMIT', 'OFFSET']:
                in_from = False
                in_join = False
                if current_join:
                    current_join['in_on'] = False
        elif in_from or in_join:
            val = token.value.strip()
            if val and val != ',' and isinstance(token, Identifier):
                table_name = token.get_name()
                if in_join:
                    result['joins'].append({
                        'table': table_name,
                        'type': join_type,
                        'alias': token.get_alias(),
                        'on_cols': []
                    })
                    current_join = result['joins'][-1]
                elif result['main_table'] is None:
                    result['main_table'] = table_name
    return result


def _parse_order_by(stmt) -> list:
    columns = []
    in_order = False
    for token in stmt.flatten():
        if token.ttype in Keyword and token.value.upper() == 'ORDER':
            in_order = True
            continue
        if token.ttype in Keyword and token.value.upper() == 'BY':
            continue
        if token.ttype in Keyword and token.value.upper() in ['LIMIT', 'OFFSET']:
            in_order = False
        if in_order and token.value.strip():
            val = token.value.strip().upper()
            if val == 'DESC':
                if columns:
                    columns[-1] = (columns[-1][0], True)
            elif val == 'ASC':
                if columns:
                    columns[-1] = (columns[-1][0], False)
            elif val != ',':
                columns.append((token.value.strip(), False))
    return columns


def extract_alias(expr: str) -> str | None:
    expr = expr.strip()
    if ' as ' in expr.lower():
        return expr.split('AS')[-1].strip().strip('"').strip("'")
    parts = expr.rsplit(' ', 1)
    if len(parts) == 2:
        alias = parts[1].strip('"').strip("'")
        if alias.upper() not in _KEYWORDS:
            try:
                float(alias)
                return None
            except ValueError:
                return alias
    return None


def find_join_key(where_expr: str, table1: str, table2: str) -> tuple | None:
    if not where_expr:
        return None
    patterns = [
        rf'{table1}\\.(\\w+)\\s*=\\s*{table2}\\.(\\w+)',
        rf'{table2}\\.(\\w+)\\s*=\\s*{table1}\\.(\\w+)',
    ]
    for pattern in patterns:
        match = re.search(pattern, where_expr, re.IGNORECASE)
        if match:
            return (match.group(1), match.group(2))
    return None

"""SQL query executor for CSV data."""

from typing import Any
import pandas as pd
from database import CSVDatabase
from query_parser import parse_query, extract_alias, find_join_key
from evaluator import SQLExpressionEvaluator


class SQLExecutor:
    """Executes SQL queries on CSV data."""

    def __init__(self, db: CSVDatabase):
        self.db = db

    def execute(self, sql: str) -> pd.DataFrame:
        return self._build_query(parse_query(sql))

    def _build_query(self, plan: dict) -> pd.DataFrame:
        df = self._load_main_table(plan['from']['main_table'])
        select_cols = self._process_select_expressions(plan['select'][0], df)

        df = self._apply_joins(df, plan['from'], plan['where'])
        if plan['where']:
            df = self._apply_where(df, plan['where'])

        group_by = plan['group_by']
        having = plan['having']
        if group_by or having:
            df = self._apply_group_by(df, group_by, select_cols, having, plan['select'][1])

        distinct = plan['select'][1]
        if distinct:
            df = self._apply_distinct(df, select_cols)

        df = self._apply_order_by(df, plan['order_by'], select_cols)
        df = self._apply_limit_offset(df, plan['limit'], plan['offset'])
        return self._build_result(df, select_cols)

    def _load_main_table(self, table_name: str) -> pd.DataFrame:
        df = self.db.get_table(table_name)
        if df is None:
            raise ValueError(f"Table '{table_name}' not found")
        return df.copy()

    def _process_select_expressions(self, select_list: list, df: pd.DataFrame) -> list:
        select_cols = []
        for expr in select_list:
            expr = expr.strip()
            upper = expr.upper()
            col = expr.split('.')[-1]

            if upper.startswith('COUNT('):
                inner = expr[6:-1].strip()
                col = '__count_all__' if inner == '*' else inner.split('.')[-1]
                alias = extract_alias(expr) or f'count_{len(select_cols)}'
            elif upper.startswith('SUM(') or upper.startswith('MIN(') or upper.startswith('MAX('):
                func = upper[:3]
                alias = extract_alias(expr) or f'{func.lower()}_{len(select_cols)}'
            else:
                alias = extract_alias(expr) or col

            agg_type_map = {'SUM': 'sum', 'MIN': 'min', 'MAX': 'max', 'COUNT': 'count'}
            agg_type = next((agg_type_map[f] for f in agg_type_map if upper.startswith(f'{f}(')), None)

            select_cols.append((alias, expr, agg_type, col))
        return select_cols

    def _apply_joins(self, df: pd.DataFrame, from_clause: dict, where_expr: str) -> pd.DataFrame:
        main = from_clause['main_table']
        for join_info in from_clause.get('joins', []):
            join_df = self.db.get_table(join_info['table'])
            if join_df is None:
                raise ValueError(f"Table '{join_info['table']}' not found")

            join_key = find_join_key(where_expr, main, join_info['table'])
            how = join_info['type'] or 'INNER'

            if join_key:
                df = pd.merge(df, join_df, left_on=join_key[0], right_on=join_key[1], how=how, suffixes=('_x', '_y'))
            else:
                df = pd.merge(df, join_df, how=how, suffixes=('_x', '_y'))
        return df

    def _apply_where(self, df: pd.DataFrame, where_expr: str) -> pd.DataFrame:
        evaluator = SQLExpressionEvaluator(self.db.tables)
        mask = df.apply(lambda row: evaluator.evaluate(where_expr, row), axis=1)
        return df[mask].copy()

    def _apply_group_by(self, df: pd.DataFrame, group_by: list, select_cols: list,
                       having: str, distinct: bool) -> pd.DataFrame:
        group_cols = [g.split('.')[-1] for g in group_by]
        existing_group_cols = [c for c in group_cols if c in df.columns]
        if not existing_group_cols:
            raise ValueError("No valid GROUP BY columns found")

        agg_dict = {}
        has_count_all = False
        for _, _, agg_type, col in select_cols:
            if agg_type == 'count' and col == '__count_all__':
                has_count_all = True
            elif agg_type and col in df.columns:
                agg_dict[col] = agg_type

        if agg_dict:
            grouped = df.groupby(existing_group_cols, as_index=False).agg(agg_dict)
            new_cols = []
            for col in grouped.columns:
                if col in existing_group_cols:
                    new_cols.append(col)
                else:
                    for alias, _, _, c in select_cols:
                        if c == col:
                            new_cols.append(alias)
                            break
                    else:
                        new_cols.append(col)
            grouped.columns = new_cols
            df = grouped
        elif has_count_all:
            df = df.groupby(existing_group_cols, as_index=False).size()
            df.columns = existing_group_cols + ['count']
        else:
            raise ValueError("No valid aggregate in SELECT with GROUP BY")

        if having and group_by:
            evaluator = SQLExpressionEvaluator(self.db.tables)
            mask = df.apply(lambda row: evaluator.evaluate(having, row), axis=1)
            df = df[mask]

        return df

    def _apply_distinct(self, df: pd.DataFrame, select_cols: list) -> pd.DataFrame:
        cols = [alias for alias, _, agg_type, col in select_cols
                if alias in df.columns and agg_type is None]
        if cols:
            df = df[cols].drop_duplicates()
        return df

    def _apply_order_by(self, df: pd.DataFrame, order_by: list, select_cols: list) -> pd.DataFrame:
        if not order_by:
            return df

        sort_cols = []
        ascending = []
        for col, desc in order_by:
            col_name = col.split('.')[-1]
            if col_name in df.columns:
                sort_cols.append(col_name)
                ascending.append(not desc)
            else:
                for alias, _, _, c in select_cols:
                    if alias == col_name:
                        sort_cols.append(alias)
                        ascending.append(not desc)
                        break

        if sort_cols:
            df = df.sort_values(by=sort_cols, ascending=ascending)
        return df

    def _apply_limit_offset(self, df: pd.DataFrame, limit: int, offset: int) -> pd.DataFrame:
        if limit is not None:
            df = df.iloc[offset:offset+limit] if offset is not None else df.head(limit)
        elif offset is not None:
            df = df.iloc[offset:]
        return df

    def _build_result(self, df: pd.DataFrame, select_cols: list) -> pd.DataFrame:
        result_cols = []
        for alias, expr, agg_type, col in select_cols:
            if alias in df.columns:
                result_cols.append(alias)
            elif agg_type == 'count' and col == '__count_all__' and 'count' in df.columns:
                result_cols.append('count')

        if not result_cols:
            result_cols = [c for c in df.columns if not c.endswith(('_x', '_y'))]

        return df[result_cols]

"""SQL expression evaluator for WHERE and HAVING clauses."""

import re
from typing import Dict
import pandas as pd


class SQLExpressionEvaluator:
    """Evaluates boolean expressions for WHERE and HAVING clauses."""

    def __init__(self, tables: Dict[str, pd.DataFrame]):
        self.tables = tables

    def evaluate(self, expr: str, row: pd.Series) -> bool:
        if not expr or not expr.strip():
            return True

        expr = expr.strip()
        expr = self._process_parentheses(expr, row)
        expr = self._process_not(expr, row)
        expr = self._replace_operators(expr)
        expr = self._handle_like(expr)
        return self._safe_eval(expr, row)

    def _process_parentheses(self, expr: str, row: pd.Series) -> str:
        while '(' in expr:
            start = expr.rfind('(')
            end = expr.find(')', start)
            if end == -1:
                break
            inner = expr[start+1:end]
            result = self.evaluate(inner, row)
            expr = expr[:start] + ('True' if result else 'False') + expr[end+1:]
        return expr

    def _process_not(self, expr: str, row: pd.Series) -> str:
        for match in re.finditer(r'\bNOT\s+(.+?)(?:\s|AND|OR|$)', expr, re.IGNORECASE):
            inner = match.group(1)
            result = self.evaluate(inner, row)
            expr = expr.replace(match.group(0), 'False' if result else 'True')
        return expr

    def _replace_operators(self, expr: str) -> str:
        expr = expr.replace('<>', '!=')
        return expr.replace('AND', 'and').replace('OR', 'or').replace('NOT', 'not') \
                   .replace('TRUE', 'True').replace('FALSE', 'False').replace('NULL', 'None')

    def _handle_like(self, expr: str) -> str:
        def convert_like(match):
            left = match.group(1).strip("'\"")
            pattern = match.group(2).strip("'\"").replace('%', '.*').replace('_', '.')
            return 'True' if re.match(pattern + '$', left, re.IGNORECASE) else 'False'

        return re.sub(
            r'(["\'\']?[^"\'\']*?)["\'\']?\s+LIKE\s+(["\'\']?[^"\'\']*?)["\'\']?',
            convert_like, expr, flags=re.IGNORECASE
        )

    def _safe_eval(self, expr: str, row: pd.Series) -> bool:
        def replace_column(match):
            col = match.group(1)
            if '.' in col:
                col = col.split('.')[-1]
            if col in row.index:
                val = row[col]
                if pd.isna(val):
                    return 'None'
                if isinstance(val, str):
                    return f"'{val}'"
                if isinstance(val, (int, float)):
                    return str(val)
            return 'None'

        expr = re.sub(r'\b(\w+)\b', replace_column, expr)
        try:
            return bool(eval(expr, {"__builtins__": {}}, {}))
        except:
            return False

"""Database layer for SQL query CLI supporting multiple file formats."""

import sys
from glob import glob
from pathlib import Path
from typing import Dict, Optional
import pandas as pd
import gzip
import bz2


SUPPORTED_FORMATS = {'.csv', '.parquet', '.tsv', '.json', '.jsonl'}
COMPRESSED_EXTENSIONS = {'.gz', '.bz2'}


def _open_compressed(filepath: Path, comp_ext: Optional[str]):
    if comp_ext == '.gz':
        return gzip.open(filepath, 'rt', encoding='utf-8')
    if comp_ext == '.bz2':
        return bz2.open(filepath, 'rt', encoding='utf-8')
    return open(filepath, 'r', encoding='utf-8')


def _read_csv(filepath, comp_ext):
    with _open_compressed(filepath, comp_ext) as f:
        return pd.read_csv(f)


def _read_parquet(filepath, comp_ext):
    return pd.read_parquet(filepath)


def _read_tsv(filepath, comp_ext):
    with _open_compressed(filepath, comp_ext) as f:
        return pd.read_csv(f, sep='\t')


def _read_json(filepath, comp_ext):
    with _open_compressed(filepath, comp_ext) as f:
        return pd.read_json(f, lines=False)


def _read_jsonl(filepath, comp_ext):
    with _open_compressed(filepath, comp_ext) as f:
        return pd.read_json(f, lines=True)


READERS = {
    '.csv': _read_csv,
    '.parquet': _read_parquet,
    '.tsv': _read_tsv,
    '.json': _read_json,
    '.jsonl': _read_jsonl,
}


def _get_format_from_path(filepath: Path) -> tuple:
    for comp in COMPRESSED_EXTENSIONS:
        if filepath.name.endswith(comp):
            name_without_comp = filepath.name[:-(len(comp))]
            for fmt in SUPPORTED_FORMATS:
                if name_without_comp.endswith(fmt):
                    return fmt, comp
            return None, None
    for fmt in SUPPORTED_FORMATS:
        if filepath.name.endswith(fmt):
            return fmt, None
    return None, None


def _load_files_from_paths(filepaths: list) -> Dict[str, pd.DataFrame]:
    """Load multiple files, grouping by base name."""
    file_groups: Dict[str, list] = {}

    for fp in map(Path, filepaths):
        fmt, comp = _get_format_from_path(fp)
        if fmt and comp:
            base = fp.name
            for c in COMPRESSED_EXTENSIONS:
                if base.endswith(c):
                    base = base[:-(len(c))]
                    break
            for f in SUPPORTED_FORMATS:
                if base.endswith(f):
                    base = base[:-(len(f))]
                    break
            file_groups.setdefault(base, []).append((fp, fmt, comp))
        elif fmt:
            base = fp.name
            for f in SUPPORTED_FORMATS:
                if base.endswith(f):
                    base = base[:-(len(f))]
                    break
            file_groups.setdefault(base, []).append((fp, fmt, None))

    tables = {}
    for base_name, files in file_groups.items():
        table_name = base_name.replace('.', '_')
        dataframes = []

        for fp, fmt, comp in files:
            try:
                df = READERS[fmt](fp, comp)
                if df is not None and len(df.columns) > 0:
                    dataframes.append(df)
            except Exception as e:
                print(f"Warning: Could not load {fp}: {e}", file=sys.stderr)

        if not dataframes:
            continue

        first = dataframes[0]
        for df in dataframes[1:]:
            if list(df.columns) != list(first.columns):
                print(f"Warning: File {fp.name} has different columns", file=sys.stderr)
            else:
                first = pd.concat([first, df], ignore_index=True)

        tables[table_name] = first

    return tables


class CSVDatabase:
    """Manages multiple file format files as database tables."""

    def __init__(self, data_dir: str):
        self.data_dir = Path(data_dir)
        self.tables: Dict[str, pd.DataFrame] = {}
        self._load_tables()

    def _load_tables(self):
        """Load all supported files from data directory."""
        filepaths = []
        for ext in SUPPORTED_FORMATS:
            for fp in self.data_dir.rglob(f"*{ext}"):
                filepaths.append(fp)
            for comp_ext in COMPRESSED_EXTENSIONS:
                for fp in self.data_dir.rglob(f"*{ext}{comp_ext}"):
                    filepaths.append(fp)

        self.tables = _load_files_from_paths(filepaths)

    def get_table(self, name: str) -> Optional[pd.DataFrame]:
        return self.tables.get(name)

    def load_sharded_tables(self, sharded_configs: list):
        """Load sharded tables from glob patterns."""
        for table_name, pattern in sharded_configs:
            filepaths = sorted(glob(pattern))
            if not filepaths:
                self.tables[table_name] = pd.DataFrame()
                continue

            tables = _load_files_from_paths(filepaths)
            if tables:
                self.tables[table_name] = list(tables.values())[0]
            else:
                self.tables[table_name] = pd.DataFrame()

