        if cols:
            df = df[cols].drop_duplicates()
        return df

    def _apply_order_by(self, df: pd.DataFrame, order_by: list, select_cols: list) -> pd.DataFrame:
        if not order_by:
            return df

        sort_cols = []
        ascending = []
        for col, desc in order_by:
            col_name = col.split('.')[-1]
            if col_name in df.columns:
